        [Fact]    public async Task Test_StaticFileServerReturnsTextFile()
        {
            // Tests serving a plain text file with Cache-Control headers.
            var baseUrl = Environment.GetEnvironmentVariable("MOCK_SERVER_URL") ?? "http://localhost:8080";
            using var handler = new System.Net.Http.HttpClientHandler { AllowAutoRedirect = false };
            using var client = new System.Net.Http.HttpClient(handler);
            var request = new System.Net.Http.HttpRequestMessage(System.Net.Http.HttpMethod.Get, $"{baseUrl}/fixtures/static_file_server_returns_text_file/public/hello.txt");
            var response = await client.SendAsync(request);
            Assert.Equal(200, (int)response.StatusCode);
            Assert.True(response.Headers.TryGetValues("cache-control", out var hdrcache_control) && hdrcache_control.Any(v => v.Contains("public, max-age=60")), "header cache-control mismatch");
            Assert.True(response.Content.Headers.TryGetValues("content-type", out var hdrcontent_type) && hdrcontent_type.Any(v => v.Contains("text/plain")), "header content-type mismatch");
            var bodyText = await response.Content.ReadAsStringAsync();
            Assert.Equal("Hello from static storage", bodyText.Trim());
        }

